{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-plus-pump-parameter-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕未连接的 Trim Cooler Outlet 流股和 Recycle Pump 的出口压力/效率参数问题生成候选提案；其中仅对已选中且有直接诊断支撑的 stream 与 unit 提供最小、可审查的局部 patch。",
      "issues": [
        {
          "title": "冷却器出口流股缺少下游去向",
          "detail": "Trim Cooler Outlet 当前未连接到任何下游设备或导出端，导致流程拓扑无效。",
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "title": "泵出口目标压力低于入口压力",
          "detail": "Recycle Pump 的 outlet_pressure_target_kpa=150，低于入口流股 pressure_kpa=190。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "泵效率参数超出建议范围",
          "detail": "Recycle Pump 的 efficiency_percent=108 超出推荐运行范围。",
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Trim Cooler Outlet 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-81"
          },
          "rationale": "诊断直接指出该流股未连接到任何下游 consumer 或 export sink。在当前证据不足以确定具体下游对象的情况下，仅建议补充连接占位以恢复可审查的拓扑意图，不预设具体设备。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "cooler-outlet-81",
              "missing_endpoint": "downstream_consumer_or_export_sink",
              "required": true
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Recycle Pump 出口目标压力提供更高于入口压力的占位修正",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "当前泵出口目标压力低于已知入口压力 190 kPa，直接触发错误。为避免在缺少工艺目标时过度设定具体数值，仅建议将目标压力改为高于入口压力的占位约束。",
          "patch": {
            "parameter_placeholders": {
              "outlet_pressure_target_kpa": {
                "constraint": "> 190",
                "basis": "must exceed inlet stream pressure_kpa on feed-81"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将 Recycle Pump 效率修正为建议范围内的占位值",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "已知 efficiency_percent=108 超出推荐范围，但当前输入未给出唯一正确值。建议仅以占位方式将其收敛回合理范围，保持最小修改。",
          "patch": {
            "parameter_placeholders": {
              "efficiency_percent": {
                "constraint": "within recommended operating range and < 108",
                "current_value": 108
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        }
      ],
      "confidence": 0.89
    }
  ],
  "citations": [
    {
      "id": "diag-1",
      "kind": "diagnostic",
      "code": "STREAM_DISCONNECTED",
      "message": "Trim Cooler Outlet is not connected to any downstream consumer or export sink."
    },
    {
